import{_ as e,o as t,c as r,Q as a}from"./chunks/framework.c4d6cd72.js";const g=JSON.parse('{"title":"How FIB works","description":"","frontmatter":{},"headers":[],"relativePath":"overview/how-fib-works.md","filePath":"overview/how-fib-works.md"}'),i={name:"overview/how-fib-works.md"},n=a('<h1 id="how-fib-works" tabindex="-1">How FIB works <a class="header-anchor" href="#how-fib-works" aria-label="Permalink to &quot;How FIB works&quot;">​</a></h1><p>FIB is a decentralized network that enables the secure sharing and analysis of data related to <a href="./fraud-events.html">fraud events</a>.</p><p>Our system allows the telco companies and vendors to register as <strong>peers</strong>. In turn, employees of these companies can register as <strong>users</strong> under their company&#39;s domain.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Peers are also considered to be users.</p></div><p>Authorized participants—<strong>peers</strong> and <strong>users</strong>—can submit information about suspected or confirmed fraudulent activities to the FIB network, where it is recorded on the blockchain. The submitted information can include details such as origin identifiers (e.g., IP addresses), the type of event, the exact time the event occurred, etc.</p><p>By sharing this information and collaborating with other peers on the network, contributors can help prevent future fraudulent activities. In return for their contributions, peers and their users can earn rewards in the form of digital credits, called <strong>tokens</strong>.</p><h2 id="data-on-the-network" tabindex="-1">Data on the network <a class="header-anchor" href="#data-on-the-network" aria-label="Permalink to &quot;Data on the network&quot;">​</a></h2><p>The FIB network serves as a secure database of various <a href="./fraud-events.html">fraud events</a> that are stored on the blockchain as <a href="./contributions.html">contributions</a>.</p><p>Registered users can upload and download these contributions.</p><p>Contributions uploaded by peers and their users allow for the continuous expansion and updating of the FIB network. This facilitates information sharing and enhances the overall accuracy of data stored on the network.</p><p>The contributions on the network can also be downloaded by peers to update their own records and stay informed about the latest fraudulent activities. This process helps organizations remain vigilant and prevent fraudulent activities from occurring within their own systems.</p><p>For more information, see <a href="./tokenomics.html#uploading-fraud-events">Uploading contributions</a> and <a href="./tokenomics.html#downloading-fraud-events">Downloading contributions</a>.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>To streamline the process of sharing fraud data, registered companies can implement their already existing system with FIB via API.</p><p>For details, see <a href="./../getting-started.html">Getting started</a>.</p></div><h2 id="network-security" tabindex="-1">Network security <a class="header-anchor" href="#network-security" aria-label="Permalink to &quot;Network security&quot;">​</a></h2><p>The security of the FIB network is crucial to ensure the safety of its users and transactions. To achieve this, the network uses scalable backend services serving requests to create and send transactions to a blockchain node securely.</p><p>The network consists of multiple nodes, which increases its resilience and availability, potentially improving its ability to recover from disruptions.</p><p>The security of the FIB network also relies on the use of key pairs and digital signatures.</p><p>There are two types of key pairs that are required to interact with the FIB API backend:</p><ol><li><a href="./web-interface.html#akp"><strong>Authorization</strong> key pair</a> — a deterministic <a href="https://en.wikipedia.org/wiki/EdDSA#Ed25519" target="_blank" rel="noreferrer">Ed25519</a> key pair generated from the user’s <strong>email</strong> and <strong>password</strong>; used for authorization on the FIB network.</li><li><a href="./web-interface.html#bkp"><strong>Blockchain</strong> key pair</a> — a deterministic <a href="https://en.wikipedia.org/wiki/EdDSA#Ed25519" target="_blank" rel="noreferrer">Ed25519</a> key pair generated from the user’s <strong>email</strong>, <strong>password</strong>, and an additional random numeric value; used for signing user transactions on the FIB network.</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>These key pairs are generated automatically for every new user during registration, and can be found at the <strong>Profile</strong> screen of the <a href="https://app.fraudintelligencelimited.com" target="_blank" rel="noreferrer">FIB Web App</a>.</p><p>For details, see the following:</p><ul><li><a href="./web-interface.html#akp">Web App UI: &#39;Authorization&#39; key pair</a></li><li><a href="./web-interface.html#bkp">Web App UI: &#39;Blockchain&#39; key pair</a></li></ul></div><p>When a user creates a transaction on the FIB network, they sign it with their private key, which can then be verified by anyone using their public key. This process ensures that only the intended user is authorized to sign their transactions.</p><p>Additionally, signing transactions with key pairs can enhance the privacy and confidentiality of the user&#39;s information on the network. Overall, the use of key pairs and digital signatures is a crucial aspect of the FIB network&#39;s security infrastructure.</p><p>For more information, see <a href="./../tutorials-api/signing-transactions.html">Signing transactions</a> and <a href="./../tutorials-api/signing-user-email-addresses.html">Signing user email addresses</a>.</p>',23),o=[n];function s(c,h,d,l,p,u){return t(),r("div",null,o)}const k=e(i,[["render",s]]);export{g as __pageData,k as default};
